    "mathml": "<math xmlns=\"http://www.w3.org/1998/Math/MathML\" display=\"block\"><semantics><mrow><msup><mrow><mi>sin</mi><mo>вҒЎ</mo></mrow><mn>2</mn></msup><mi>Оё</mi><mo>+</mo><msup><mrow><mi>cos</mi><mo>вҒЎ</mo></mrow><mn>2</mn></msup><mi>Оё</mi><mo>=</mo><mn>1</mn><mo separator=\"true\">;</mo><mtext>вҖ…вҖҠ</mtext><mn>1</mn><mo>+</mo><msup><mrow><mi>tan</mi><mo>вҒЎ</mo></mrow><mn>2</mn></msup><mi>Оё</mi><mo>=</mo><msup><mrow><mi>sec</mi><mo>вҒЎ</mo></mrow><mn>2</mn></msup><mi>Оё</mi><mo separator=\"true\">;</mo><mtext>вҖ…вҖҠ</mtext><mn>1</mn><mo>+</mo><msup><mrow><mi>cot</mi><mo>вҒЎ</mo></mrow><mn>2</mn></msup><mi>Оё</mi><mo>=</mo><msup><mrow><mi>csc</mi><mo>вҒЎ</mo></mrow><mn>2</mn></msup><mi>Оё</mi></mrow><annotation encoding=\"application/x-tex\">\\sin^2\\theta + \\cos^2\\theta = 1;\\; 1 + \\tan^2\\theta = \\sec^2\\theta;\\; 1 + \\cot^2\\theta = \\csc^2\\theta</annotation></semantics></math>",
